{
  "name": "SkinForge",
  "description": "Premium smartphone skin creator. Design, customize, and print precise back-cover templates for iPhone, Samsung, and Pixel devices."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum Brand {
  APPLE = 'Apple',
  SAMSUNG = 'Samsung',
  GOOGLE = 'Google'
}

export interface CameraCutout {
  type: 'path' | 'circle' | 'rect';
  data: string; // SVG Path data or coordinate string
}

export interface PhoneModel {
  id: string;
  name: string;
  brand: Brand;
  widthMm: number;
  heightMm: number;
  cornerRadiusMm: number;
  // Simplified camera representation for the demo
  // In a real app, this would be complex SVG paths
  cameraPath: string; 
  releaseYear: number;
}

export interface EditState {
  scale: number;
  translateX: number;
  translateY: number;
  rotation: number;
}

import { EditState, PhoneModel } from '../types';
import { PX_PER_MM } from '../constants';

export const generatePrintableImage = (
  model: PhoneModel,
  imageUrl: string,
  editState: EditState
): Promise<string> => {
  return new Promise((resolve, reject) => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = imageUrl;

    img.onload = () => {
      if (!ctx) return reject('No context');

      // 1. Setup Canvas Dimensions (300 DPI)
      // Add padding for the "Paper" context so user can cut it out
      const paddingMm = 10;
      const totalWidthMm = model.widthMm + (paddingMm * 2);
      const totalHeightMm = model.heightMm + (paddingMm * 2);

      canvas.width = totalWidthMm * PX_PER_MM;
      canvas.height = totalHeightMm * PX_PER_MM;

      const phoneX = paddingMm * PX_PER_MM;
      const phoneY = paddingMm * PX_PER_MM;
      const phoneW = model.widthMm * PX_PER_MM;
      const phoneH = model.heightMm * PX_PER_MM;
      const radius = model.cornerRadiusMm * PX_PER_MM;

      // Fill Background White (The Paper)
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Save state before masking
      ctx.save();

      // 2. Create the Phone Shape Mask
      ctx.beginPath();
      ctx.roundRect(phoneX, phoneY, phoneW, phoneH, radius);
      ctx.clip(); // Everything drawn after this stays inside the phone shape

      // 3. Draw the User Image
      // We need to map the UI percentage coordinates back to these high-res pixels
      // The editState.scale is a multiplier. 1 = image fits width or height.
      // translate is in percentage of the container.

      const imgAspect = img.width / img.height;
      const phoneAspect = model.widthMm / model.heightMm;

      let drawWidth, drawHeight;
      if (imgAspect > phoneAspect) {
        // Image is wider than phone
        drawHeight = phoneH * editState.scale;
        drawWidth = drawHeight * imgAspect;
      } else {
        // Image is taller than phone
        drawWidth = phoneW * editState.scale;
        drawHeight = drawWidth / imgAspect;
      }

      // Calculate Center Position
      const centerX = phoneX + (phoneW / 2);
      const centerY = phoneY + (phoneH / 2);

      // Apply offset (translateX is % of phone width)
      const offsetX = (editState.translateX / 100) * phoneW;
      const offsetY = (editState.translateY / 100) * phoneH;

      ctx.translate(centerX + offsetX, centerY + offsetY);
      ctx.rotate((editState.rotation * Math.PI) / 180);

      // Draw image centered at current origin
      ctx.drawImage(img, -drawWidth / 2, -drawHeight / 2, drawWidth, drawHeight);

      // Restore to remove clip for the next steps
      ctx.restore();

      // 4. Cut out the Camera (Destination Out)
      // We need to parse the path or use the simple approximation from constants
      // Note: The SVG path data in constants is in MM. We need to scale it.
      ctx.save();
      ctx.translate(phoneX, phoneY); // Move to phone origin
      ctx.scale(PX_PER_MM, PX_PER_MM); // Scale coordinate system so 1 unit = 1mm

      ctx.globalCompositeOperation = 'destination-out';
      ctx.fillStyle = 'black';

      const p = new Path2D(model.cameraPath);
      ctx.fill(p);

      ctx.restore();

      // 5. Draw Cutting Guide (Border)
      ctx.save();
      ctx.lineWidth = 2; // Thin line
      ctx.strokeStyle = '#cccccc'; // Light gray cutting line
      ctx.beginPath();
      ctx.roundRect(phoneX, phoneY, phoneW, phoneH, radius);
      ctx.stroke();

      // Draw Camera Cutting Guide
      ctx.translate(phoneX, phoneY);
      ctx.scale(PX_PER_MM, PX_PER_MM);
      ctx.lineWidth = 1 / PX_PER_MM; // 1 pixel width equivalent
      ctx.stroke(new Path2D(model.cameraPath));

      ctx.restore();

      // 6. Add Scale Reference (Ruler)
      ctx.fillStyle = '#000000';
      ctx.font = `${10 * PX_PER_MM / 2.5}px Arial`; // Approx 10pt font
      ctx.fillText(`SkinForge - ${model.name}`, phoneX, phoneY - 20);

      // 1 Inch Line
      const inchPx = 25.4 * PX_PER_MM;
      ctx.fillRect(phoneX, canvas.height - 40, inchPx, 5);
      ctx.fillText('1 inch / 2.54 cm scale check', phoneX, canvas.height - 50);

      resolve(canvas.toDataURL('image/png'));
    };

    img.onerror = (e) => reject(e);
  });
};

import React, { useState } from 'react';
import { PhoneModel, Brand } from '../types';
import { PHONE_MODELS } from '../constants';
import { Search, ChevronRight } from 'lucide-react';

interface Props {
  onSelect: (model: PhoneModel) => void;
}

export const ModelSelector: React.FC<Props> = ({ onSelect }) => {
  const [activeBrand, setActiveBrand] = useState<Brand | 'All'>('All');
  const [search, setSearch] = useState('');

  const filteredModels = PHONE_MODELS.filter(m => {
    const matchesBrand = activeBrand === 'All' || m.brand === activeBrand;
    const matchesSearch = m.name.toLowerCase().includes(search.toLowerCase());
    return matchesBrand && matchesSearch;
  });

  return (
    <div className="w-full max-w-4xl mx-auto p-4 md:p-8 animate-fade-in">
      <div className="text-center mb-10">
        <h1 className="text-3xl md:text-5xl font-bold text-white mb-4">
          Select your <span className="text-transparent bg-clip-text bg-gradient-to-r from-brand-400 to-violet-400">Device</span>
        </h1>
        <p className="text-zinc-400">Precision cut templates for popular smartphones.</p>
      </div>

      {/* Filters */}
      <div className="flex flex-col md:flex-row gap-4 mb-8 justify-between items-center">
        <div className="flex gap-2 p-1 bg-white/5 rounded-xl border border-white/5 overflow-x-auto max-w-full">
          {['All', ...Object.values(Brand)].map(brand => (
            <button
              key={brand}
              onClick={() => setActiveBrand(brand as Brand | 'All')}
              className={`px-4 py-2 rounded-lg text-sm font-medium transition-all whitespace-nowrap ${
                activeBrand === brand 
                  ? 'bg-brand-600 text-white shadow-lg shadow-brand-900/50' 
                  : 'text-zinc-400 hover:text-white hover:bg-white/5'
              }`}
            >
              {brand}
            </button>
          ))}
        </div>

        <div className="relative w-full md:w-64">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-zinc-500" size={16} />
          <input 
            type="text" 
            placeholder="Search model..." 
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full bg-white/5 border border-white/10 rounded-xl pl-10 pr-4 py-2.5 text-sm text-white placeholder-zinc-600 focus:outline-none focus:ring-2 focus:ring-brand-500/50"
          />
        </div>
      </div>

      {/* Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
        {filteredModels.map(model => (
          <button
            key={model.id}
            onClick={() => onSelect(model)}
            className="group relative bg-zinc-900/50 border border-white/5 hover:border-brand-500/50 hover:bg-zinc-800/50 rounded-2xl p-6 text-left transition-all duration-300 overflow-hidden"
          >
            <div className="absolute inset-0 bg-gradient-to-br from-brand-500/0 to-violet-500/0 group-hover:from-brand-500/5 group-hover:to-violet-500/5 transition-all" />

            <div className="relative z-10 flex justify-between items-start">
              <div>
                <span className="text-xs font-semibold text-brand-400 mb-1 block uppercase tracking-wider">{model.brand}</span>
                <h3 className="text-lg font-bold text-white group-hover:text-brand-100 transition-colors">{model.name}</h3>
                <p className="text-zinc-500 text-sm mt-1">{model.widthMm}mm x {model.heightMm}mm</p>
              </div>
              <div className="w-8 h-8 rounded-full bg-white/5 flex items-center justify-center group-hover:bg-brand-500 group-hover:text-white transition-all">
                <ChevronRight size={16} />
              </div>
            </div>

            {/* Simple wireframe preview */}
            <div className="mt-6 flex justify-center opacity-30 group-hover:opacity-50 transition-opacity">
              <div 
                style={{ 
                  width: model.widthMm * 0.8, 
                  height: model.heightMm * 0.8,
                  borderRadius: model.cornerRadiusMm * 0.8,
                }} 
                className="border-2 border-dashed border-white"
              />
            </div>
          </button>
        ))}
      </div>

      {filteredModels.length === 0 && (
        <div className="text-center py-20">
          <p className="text-zinc-500">No models found matching "{search}"</p>
        </div>
      )}
    </div>
  );
};

import React, { useState, useRef, useEffect } from 'react';
import { PhoneModel, EditState } from '../types';
import { DEFAULT_PATTERNS } from '../constants';
import { generatePrintableImage } from '../utils/canvasUtils';
import { Upload, RotateCcw, ZoomIn, ZoomOut, Download, Move, ArrowLeft } from 'lucide-react';

interface Props {
  model: PhoneModel;
  onBack: () => void;
}

export const ImageCustomizer: React.FC<Props> = ({ model, onBack }) => {
  const [image, setImage] = useState<string | null>(null);
  const [editState, setEditState] = useState<EditState>({
    scale: 1,
    translateX: 0,
    translateY: 0,
    rotation: 0
  });
  const [isDragging, setIsDragging] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [isGenerating, setIsGenerating] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);

  // File Upload
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => setImage(ev.target?.result as string);
      reader.readAsDataURL(file);
    }
  };

  // Mouse / Touch Interactions for Dragging
  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!image) return;
    setIsDragging(true);
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
    setDragStart({ x: clientX, y: clientY });
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!isDragging || !containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    const deltaX = clientX - dragStart.x;
    const deltaY = clientY - dragStart.y;

    // Convert pixels to percentage of container to remain responsive
    const rect = containerRef.current.getBoundingClientRect();
    const percentX = (deltaX / rect.width) * 100;
    const percentY = (deltaY / rect.height) * 100;

    setEditState(prev => ({
      ...prev,
      translateX: prev.translateX + percentX,
      translateY: prev.translateY + percentY
    }));

    setDragStart({ x: clientX, y: clientY });
  };

  const handleMouseUp = () => setIsDragging(false);

  // Download Handler
  const handleDownload = async () => {
    if (!image) return;
    setIsGenerating(true);
    try {
      const dataUrl = await generatePrintableImage(model, image, editState);
      const link = document.createElement('a');
      link.download = `SkinForge-${model.name.replace(/\s+/g, '-')}-Template.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error(err);
      alert('Failed to generate image. Please try a different browser or image.');
    } finally {
      setIsGenerating(false);
    }
  };

  // Visual Setup
  // We need to render the Phone shape using CSS Aspect Ratio based on MM dimensions
  const aspectRatio = `${model.widthMm} / ${model.heightMm}`;

  // Scale the SVG Path for CSS display (rough approximation for display only)
  // The actual printing uses the Canvas logic which handles the SVG path correctly.
  // For display, we just use a generic mask or a pre-defined ID based masking if needed.
  // To keep it simple but functional: We will use a standard "Masking" div structure.

  return (
    <div className="flex flex-col lg:flex-row h-[calc(100vh-64px)] overflow-hidden">

      {/* LEFT: Controls */}
      <div className="w-full lg:w-96 bg-zinc-900 border-r border-white/5 p-6 flex flex-col gap-6 overflow-y-auto z-10 shadow-2xl">
        <button onClick={onBack} className="flex items-center gap-2 text-zinc-400 hover:text-white transition-colors mb-2">
          <ArrowLeft size={16} /> Back to models
        </button>

        <div>
          <h2 className="text-2xl font-bold text-white mb-1">{model.name}</h2>
          <p className="text-zinc-500 text-sm">Upload an image to start customization.</p>
        </div>

        {/* Upload */}
        <div className="space-y-4">
          <label className="flex flex-col items-center justify-center w-full h-32 border-2 border-dashed border-white/10 rounded-xl hover:border-brand-500/50 hover:bg-brand-500/5 transition-all cursor-pointer group">
            <div className="flex flex-col items-center justify-center pt-5 pb-6">
              <Upload className="w-8 h-8 text-zinc-500 group-hover:text-brand-400 mb-2" />
              <p className="text-sm text-zinc-400">Click to upload image</p>
            </div>
            <input type="file" className="hidden" accept="image/*" onChange={handleFileUpload} />
          </label>

          {/* Presets */}
          <div className="grid grid-cols-5 gap-2">
            {DEFAULT_PATTERNS.map((url, i) => (
              <button 
                key={i}
                onClick={() => setImage(url)}
                className="aspect-square rounded-lg overflow-hidden border border-white/10 hover:border-brand-500 transition-all"
              >
                <img src={url} alt="Preset" className="w-full h-full object-cover" />
              </button>
            ))}
          </div>
        </div>

        {/* Controls */}
        {image && (
          <div className="space-y-6 animate-fade-in">
            <div className="space-y-3">
              <div className="flex justify-between text-sm text-zinc-400">
                <span>Scale</span>
                <span>{Math.round(editState.scale * 100)}%</span>
              </div>
              <input 
                type="range" 
                min="0.5" 
                max="3" 
                step="0.05" 
                value={editState.scale}
                onChange={(e) => setEditState({...editState, scale: parseFloat(e.target.value)})}
                className="w-full accent-brand-500 bg-white/10 h-2 rounded-lg appearance-none cursor-pointer"
              />
              <div className="flex justify-between gap-2">
                <button 
                  onClick={() => setEditState(s => ({...s, scale: Math.max(0.1, s.scale - 0.1)}))}
                  className="p-2 bg-white/5 rounded-lg hover:bg-white/10 text-zinc-400"
                >
                  <ZoomOut size={16} />
                </button>
                <button 
                  onClick={() => setEditState(s => ({...s, scale: s.scale + 0.1}))}
                  className="p-2 bg-white/5 rounded-lg hover:bg-white/10 text-zinc-400"
                >
                  <ZoomIn size={16} />
                </button>
              </div>
            </div>

            <div className="space-y-3">
              <div className="flex justify-between text-sm text-zinc-400">
                <span>Rotation</span>
                <span>{Math.round(editState.rotation)}°</span>
              </div>
              <input 
                type="range" 
                min="0" 
                max="360" 
                step="90" 
                value={editState.rotation}
                onChange={(e) => setEditState({...editState, rotation: parseInt(e.target.value)})}
                className="w-full accent-brand-500 bg-white/10 h-2 rounded-lg appearance-none cursor-pointer"
              />
              <button 
                onClick={() => setEditState({...editState, rotation: (editState.rotation + 90) % 360})}
                className="w-full py-2 flex items-center justify-center gap-2 bg-white/5 rounded-lg hover:bg-white/10 text-zinc-400 text-sm"
              >
                <RotateCcw size={14} /> Rotate 90°
              </button>
            </div>
          </div>
        )}

        <div className="mt-auto pt-6 border-t border-white/5">
          <button
            onClick={handleDownload}
            disabled={!image || isGenerating}
            className={`w-full py-4 rounded-xl font-bold flex items-center justify-center gap-2 transition-all ${
              !image 
                ? 'bg-zinc-800 text-zinc-600 cursor-not-allowed' 
                : 'bg-gradient-to-r from-brand-600 to-violet-600 hover:from-brand-500 hover:to-violet-500 text-white shadow-lg shadow-brand-900/50'
            }`}
          >
            {isGenerating ? (
              <span className="animate-pulse">Generating...</span>
            ) : (
              <>
                <Download size={20} /> Download Template
              </>
            )}
          </button>
          <p className="text-xs text-center text-zinc-600 mt-3">
            Download includes a 1:1 scale reference. Print at 100% scale.
          </p>
        </div>
      </div>

      {/* RIGHT: Workspace */}
      <div className="flex-1 bg-black relative flex items-center justify-center p-8 lg:p-12 overflow-hidden">
        {/* Background Grid */}
        <div 
          className="absolute inset-0 opacity-10 pointer-events-none" 
          style={{ backgroundImage: 'radial-gradient(circle, #333 1px, transparent 1px)', backgroundSize: '24px 24px' }} 
        />

        {!image && (
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none z-0">
            <div className="text-zinc-800 font-bold text-6xl md:text-9xl opacity-20 select-none">
              PREVIEW
            </div>
          </div>
        )}

        {/* Phone Container */}
        <div 
          className="relative shadow-2xl transition-all duration-500 ease-out"
          style={{
            aspectRatio,
            height: 'min(80vh, 600px)', // Max height constraint
            borderRadius: `${model.cornerRadiusMm}mm`, // CSS can use mm units, neat!
          }}
        >
          {/* Main Mask Wrapper */}
          <div 
            ref={containerRef}
            className="w-full h-full relative overflow-hidden bg-zinc-900 cursor-move"
            style={{ borderRadius: 'inherit' }}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={handleMouseUp}
            onMouseLeave={handleMouseUp}
            onTouchStart={handleMouseDown}
            onTouchMove={handleMouseMove}
            onTouchEnd={handleMouseUp}
          >
            {image ? (
              <img 
                src={image}
                alt="Upload"
                draggable={false}
                className="absolute origin-center max-w-none select-none"
                style={{
                  top: '50%',
                  left: '50%',
                  width: `${editState.scale * 100}%`,
                  transform: `translate(-50%, -50%) translate(${editState.translateX}%, ${editState.translateY}%) rotate(${editState.rotation}deg)`,
                }}
              />
            ) : (
               <div className="w-full h-full flex items-center justify-center text-zinc-600 flex-col gap-2">
                 <Move size={32} className="opacity-50" />
                 <span className="text-sm">Drag to position</span>
               </div>
            )}

            {/* Camera Overlay (Visual Approximation) */}
            {/* We overlay a black SVG path to simulate the camera hole visually */}
            <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-10">
               <svg 
                viewBox={`0 0 ${model.widthMm} ${model.heightMm}`} 
                className="w-full h-full"
                preserveAspectRatio="none"
               >
                 <path d={model.cameraPath} fill="rgba(0,0,0,0.8)" />
                 {/* Add a subtle highlight to the camera cutout border */}
                 <path d={model.cameraPath} fill="none" stroke="rgba(255,255,255,0.2)" strokeWidth="0.5" />
               </svg>
            </div>
          </div>

          {/* Glossy Overlay Reflection */}
          <div 
            className="absolute inset-0 pointer-events-none z-20 rounded-[inherit] border border-white/10 ring-1 ring-black/50"
            style={{
              background: 'linear-gradient(120deg, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0) 40%, rgba(255,255,255,0) 100%)'
            }}
          />
        </div>
      </div>
    </div>
  );
};

import React, { useState } from 'react';
import { Header } from './components/Header';
import { ModelSelector } from './components/ModelSelector';
import { ImageCustomizer } from './components/ImageCustomizer';
import { PhoneModel } from './types';

const App: React.FC = () => {
  const [selectedModel, setSelectedModel] = useState<PhoneModel | null>(null);

  return (
    <div className="min-h-screen bg-black text-white selection:bg-brand-500/30">
      <Header />

      <main>
        {!selectedModel ? (
          <ModelSelector onSelect={setSelectedModel} />
        ) : (
          <ImageCustomizer 
            model={selectedModel} 
            onBack={() => setSelectedModel(null)} 
          />
        )}
      </main>
    </div>
  );
};

export default App;

