              }`}
            >
              {isGenerating ? <span className="animate-pulse">Rendering...</span> : <><Download size={18} /> Export PDF/PNG</>}
            </button>
          </div>
        </div>
      </div>

      {/* -------------------------------------------------------------
          RIGHT WORKSPACE
         ------------------------------------------------------------- */}
      <div className="flex-1 relative bg-black flex items-center justify-center p-8 overflow-hidden">
        {/* Background Grid */}
        <div 
          className="absolute inset-0 opacity-20 pointer-events-none" 
          style={{ backgroundImage: 'radial-gradient(circle, #333 1px, transparent 1px)', backgroundSize: '30px 30px' }} 
        />

        {/* Workspace Info */}
        <div className="absolute top-6 right-6 flex items-center gap-4 z-30">
           <div className="px-3 py-1 bg-zinc-900/80 backdrop-blur rounded-full border border-white/5 text-xs text-zinc-400">
             {model.name} — {model.widthMm}mm x {model.heightMm}mm
           </div>
        </div>

        {!image && (
          <div className="absolute inset-0 flex flex-col items-center justify-center pointer-events-none z-0 text-zinc-800">
             <div className="text-8xl font-black opacity-20 tracking-tighter">CREATE</div>
             <p className="opacity-40 font-mono mt-4">Import an image to begin designing</p>
          </div>
        )}

        {/* PHONE CANVAS */}
        <div 
          className="relative shadow-2xl transition-all duration-300 ease-out z-10 ring-1 ring-white/10"
          style={{
            aspectRatio: `${model.widthMm} / ${model.heightMm}`,
            height: 'min(85vh, 700px)',
            borderRadius: `${model.cornerRadiusMm}mm`,
          }}
        >
          {/* Mask & Interactive Area */}
          <div 
            ref={containerRef}
            className={`w-full h-full relative overflow-hidden bg-zinc-900 ${image ? 'cursor-move' : ''}`}
            style={{ borderRadius: 'inherit' }}
            onMouseDown={handleMouseDown}
            onMouseMove={handleMouseMove}
            onMouseUp={() => setIsDragging(false)}
            onMouseLeave={() => setIsDragging(false)}
            onTouchStart={handleMouseDown}
            onTouchMove={handleMouseMove}
            onTouchEnd={() => setIsDragging(false)}
          >
            {image && (
              <img 
                src={image}
                alt="Design"
                draggable={false}
                className="absolute origin-center max-w-none select-none"
                style={{
                  top: '50%',
                  left: '50%',
                  width: `${editState.scale * 100}%`,
                  transform: `
                    translate(-50%, -50%) 
                    translate(${editState.translateX}%, ${editState.translateY}%) 
                    rotate(${editState.rotation}deg)
                    scaleX(${editState.flipX ? -1 : 1})
                    scaleY(${editState.flipY ? -1 : 1})
                  `,
                  filter: previewFilter
                }}
              />
            )}

            {/* Camera Overlay */}
            <div className="absolute top-0 left-0 w-full h-full pointer-events-none z-20">
               <svg viewBox={`0 0 ${model.widthMm} ${model.heightMm}`} className="w-full h-full" preserveAspectRatio="none">
                 <path d={model.cameraPath} fill="rgba(0,0,0,0.85)" />
                 <path d={model.cameraPath} fill="none" stroke="rgba(255,255,255,0.3)" strokeWidth="0.5" />
               </svg>
            </div>

            {/* Gloss */}
            <div className="absolute inset-0 pointer-events-none z-30 opacity-50 bg-gradient-to-tr from-white/10 via-transparent to-transparent" />
          </div>
        </div>
      </div>
    </div>
  );
};

export enum Brand {
  APPLE = 'Apple',
  SAMSUNG = 'Samsung',
  GOOGLE = 'Google'
}

export interface CameraCutout {
  type: 'path' | 'circle' | 'rect';
  data: string; // SVG Path data or coordinate string
}

export interface PhoneModel {
  id: string;
  name: string;
  brand: Brand;
  widthMm: number;
  heightMm: number;
  cornerRadiusMm: number;
  // Simplified camera representation for the demo
  // In a real app, this would be complex SVG paths
  cameraPath: string; 
  releaseYear: number;
}

export interface TextLayer {
  id: string;
  text: string;
  fontFamily: string;
  color: string;
  fontSize: number; // percentage of phone width
  x: number; // percentage X (0-100)
  y: number; // percentage Y (0-100)
  rotation: number;
}

export interface EditState {
  scale: number;
  translateX: number;
  translateY: number;
  rotation: number;
  // Image Adjustments
  brightness: number; // 100 default
  contrast: number;   // 100 default
  saturation: number; // 100 default
  grayscale: number;  // 0 default
  blur: number;       // 0 default
  // Transforms
  flipX: boolean;
  flipY: boolean;
  // Text
  textLayers: TextLayer[];
}

import { EditState, PhoneModel } from '../types';
import { PX_PER_MM } from '../constants';

const A4_WIDTH_MM = 210;
const A4_HEIGHT_MM = 297;

export const generatePrintableImage = (
  model: PhoneModel,
  imageUrl: string,
  editState: EditState
): Promise<string> => {
  return new Promise((resolve, reject) => {
    const canvas = document.createElement('canvas');
    const ctx = canvas.getContext('2d');
    const img = new Image();
    img.crossOrigin = "anonymous";
    img.src = imageUrl;

    img.onload = () => {
      if (!ctx) return reject('No context');

      // 1. Setup Canvas Dimensions (A4 at 300 DPI)
      canvas.width = A4_WIDTH_MM * PX_PER_MM;
      canvas.height = A4_HEIGHT_MM * PX_PER_MM;

      // Fill Background White (Paper Color)
      ctx.fillStyle = '#ffffff';
      ctx.fillRect(0, 0, canvas.width, canvas.height);

      // Calculations for centering the phone on the A4 page
      const phoneW = model.widthMm * PX_PER_MM;
      const phoneH = model.heightMm * PX_PER_MM;
      const skinX = (canvas.width - phoneW) / 2;
      const skinY = (canvas.height - phoneH) / 2;
      const radius = model.cornerRadiusMm * PX_PER_MM;

      // ----------------------------------------------------------
      // 2. Draw the Phone Skin
      // ----------------------------------------------------------

      // Save state for clipping
      ctx.save();
      ctx.translate(skinX, skinY);

      // Create Mask
      ctx.beginPath();
      if (ctx.roundRect) {
        ctx.roundRect(0, 0, phoneW, phoneH, radius);
      } else {
        ctx.rect(0, 0, phoneW, phoneH);
      }
      ctx.clip(); 

      // Draw User Image
      const imgAspect = img.width / img.height;
      const phoneAspect = model.widthMm / model.heightMm;

      let drawWidth, drawHeight;
      if (imgAspect > phoneAspect) {
        // Image is wider relative to phone
        drawHeight = phoneH * editState.scale;
        drawWidth = drawHeight * imgAspect;
      } else {
        // Image is taller relative to phone
        drawWidth = phoneW * editState.scale;
        drawHeight = drawWidth / imgAspect;
      }

      const centerX = phoneW / 2;
      const centerY = phoneH / 2;

      const offsetX = (editState.translateX / 100) * phoneW;
      const offsetY = (editState.translateY / 100) * phoneH;

      ctx.save(); // Save before transform for image
      ctx.translate(centerX + offsetX, centerY + offsetY);
      ctx.rotate((editState.rotation * Math.PI) / 180);

      // Apply Flip
      const scaleX = editState.flipX ? -1 : 1;
      const scaleY = editState.flipY ? -1 : 1;
      ctx.scale(scaleX, scaleY);

      // Apply Filters
      // Note: filter string syntax matches CSS
      ctx.filter = `brightness(${editState.brightness}%) contrast(${editState.contrast}%) saturate(${editState.saturation}%) grayscale(${editState.grayscale}%) blur(${editState.blur * (PX_PER_MM/4)}px)`; 

      ctx.drawImage(img, -drawWidth / 2, -drawHeight / 2, drawWidth, drawHeight);
      ctx.restore(); // Restore after image draw, but keep clip

      // ----------------------------------------------------------
      // 2.5 Draw Text Layers
      // ----------------------------------------------------------
      if (editState.textLayers && editState.textLayers.length > 0) {
        editState.textLayers.forEach(layer => {
          ctx.save();
          // Position relative to phone bounding box
          const x = (layer.x / 100) * phoneW;
          const y = (layer.y / 100) * phoneH;

          ctx.translate(x, y);
          ctx.rotate((layer.rotation * Math.PI) / 180);

          // Calculate font size relative to phone width (mm -> px)
          // layer.fontSize is in percent of phone width. 
          const fontSizePx = (layer.fontSize / 100) * phoneW;

          ctx.font = `${fontSizePx}px ${layer.fontFamily}`;
          ctx.fillStyle = layer.color;
          ctx.textAlign = 'center';
          ctx.textBaseline = 'middle';
          ctx.fillText(layer.text, 0, 0);

          ctx.restore();
        });
      }

      ctx.restore(); // Restore clip

      // ----------------------------------------------------------
      // 3. Cut out Camera
      // ----------------------------------------------------------
      ctx.save();
      ctx.translate(skinX, skinY);
      ctx.scale(PX_PER_MM, PX_PER_MM);
      ctx.globalCompositeOperation = 'destination-out';
      ctx.fillStyle = 'black';
      const p = new Path2D(model.cameraPath);
      ctx.fill(p);
      ctx.restore();

      // ----------------------------------------------------------
      // 4. Draw Cutting Guides
      // ----------------------------------------------------------
      ctx.save();
      ctx.translate(skinX, skinY);

      // Outer Border (Dashed for cutting)
      ctx.lineWidth = 2; 
      ctx.strokeStyle = '#666666'; 
      ctx.setLineDash([15, 10]); 
      ctx.beginPath();
      if (ctx.roundRect) {
        ctx.roundRect(0, 0, phoneW, phoneH, radius);
      } else {
        ctx.rect(0, 0, phoneW, phoneH);
      }
      ctx.stroke();

      // Camera Border
      ctx.scale(PX_PER_MM, PX_PER_MM);
      ctx.lineWidth = 1 / PX_PER_MM; 
      ctx.setLineDash([5, 5]);
      ctx.stroke(new Path2D(model.cameraPath));
      ctx.restore();

      // ----------------------------------------------------------
      // 5. Page Layout & Info
      // ----------------------------------------------------------
      ctx.fillStyle = '#111827'; // Dark gray text
      const marginPx = 20 * PX_PER_MM;

      // Title
      ctx.font = `bold ${16 * PX_PER_MM / 2.54}px sans-serif`;
      ctx.fillText("SkinForge Template", marginPx, marginPx);

      // Subtitle / Instructions
      ctx.font = `${10 * PX_PER_MM / 2.54}px sans-serif`;
      let textY = marginPx + (30 * PX_PER_MM / 2.54);
      ctx.fillText(`Device: ${model.name}`, marginPx, textY);

      textY += (20 * PX_PER_MM / 2.54);
      ctx.fillStyle = '#dc2626'; // Red warning
      ctx.font = `bold ${11 * PX_PER_MM / 2.54}px sans-serif`;
      ctx.fillText("IMPORTANT: PRINT AT 100% SCALE (DO NOT 'FIT TO PAGE')", marginPx, textY);

      textY += (20 * PX_PER_MM / 2.54);
      ctx.fillStyle = '#4b5563';
      ctx.font = `${9 * PX_PER_MM / 2.54}px sans-serif`;
      ctx.fillText("Ensure page size is set to A4 in printer settings.", marginPx, textY);


      // ----------------------------------------------------------
      // 6. Accurate Scale Ruler
      // ----------------------------------------------------------
      // 10cm Ruler
      const rulerY = canvas.height - marginPx - (20 * PX_PER_MM);
      const rulerX = marginPx;
      const rulerLenMm = 100; // 10cm
      const rulerLenPx = rulerLenMm * PX_PER_MM;

      ctx.strokeStyle = '#000000';
      ctx.lineWidth = 2;
      ctx.setLineDash([]); // Reset dash
      ctx.beginPath();
      ctx.moveTo(rulerX, rulerY);
      ctx.lineTo(rulerX + rulerLenPx, rulerY);
      ctx.stroke();

      ctx.fillStyle = '#000000';
      ctx.font = `${8 * PX_PER_MM / 2.54}px sans-serif`;

      for(let i=0; i<=10; i++) {
        const x = rulerX + (i * 10 * PX_PER_MM);
        const h = i % 5 === 0 ? (8 * PX_PER_MM) : (4 * PX_PER_MM); // Tick height
        ctx.fillRect(x, rulerY, 2, h); // Draw tick

        if (i % 5 === 0) {
          ctx.fillText(`${i}cm`, x - (5 * PX_PER_MM), rulerY + h + (10 * PX_PER_MM));
        }
      }

      ctx.fillText("SCALE CHECK (10cm)", rulerX + rulerLenPx + (10 * PX_PER_MM), rulerY + (5 * PX_PER_MM));

      // Branding watermark bottom right
      ctx.textAlign = 'right';
      ctx.fillStyle = '#e5e7eb';
      ctx.font = `bold ${32 * PX_PER_MM / 2.54}px sans-serif`;
      ctx.fillText("SkinForge", canvas.width - marginPx, canvas.height - marginPx);

      resolve(canvas.toDataURL('image/png'));
    };

    img.onerror = (e) => reject(e);
  });
};

import React, { useState, useRef } from 'react';
import { PhoneModel, EditState, TextLayer } from '../types';
import { DEFAULT_PATTERNS, FONTS } from '../constants';
import { generatePrintableImage } from '../utils/canvasUtils';
import { 
  Upload, Sliders, Move, ArrowLeft, Download, 
  RotateCcw, ZoomIn, ZoomOut, FlipHorizontal, FlipVertical,
  Image as ImageIcon, RefreshCw, Sun, Contrast, Droplet, EyeOff, Aperture,
  Type, Plus, Trash2, X
} from 'lucide-react';

interface Props {
  model: PhoneModel;
  onBack: () => void;
}

const INITIAL_STATE: EditState = {
  scale: 1,
  translateX: 0,
  translateY: 0,
  rotation: 0,
  brightness: 100,
  contrast: 100,
  saturation: 100,
  grayscale: 0,
  blur: 0,
  flipX: false,
  flipY: false,
  textLayers: []
};

type ToolTab = 'upload' | 'adjust' | 'transform' | 'text';

export const ImageCustomizer: React.FC<Props> = ({ model, onBack }) => {
  const [image, setImage] = useState<string | null>(null);
  const [editState, setEditState] = useState<EditState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<ToolTab>('upload');
  const [activeTextId, setActiveTextId] = useState<string | null>(null);

  const [isDraggingImage, setIsDraggingImage] = useState(false);
  const [isDraggingText, setIsDraggingText] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [isGenerating, setIsGenerating] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);

  // File Upload
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setImage(ev.target?.result as string);
        setEditState({ ...INITIAL_STATE, textLayers: [] }); 
        setActiveTab('transform'); 
      };
      reader.readAsDataURL(file);
    }
  };

  // Canvas Generation
  const handleDownload = async () => {
    if (!image) return;
    setIsGenerating(true);
    try {
      const dataUrl = await generatePrintableImage(model, image, editState);
      const link = document.createElement('a');
      link.download = `SkinForge-${model.name.replace(/\s+/g, '-')}-Template.png`;
      link.href = dataUrl;
      link.click();
    } catch (err) {
      console.error(err);
      alert('Failed to generate image.');
    } finally {
      setIsGenerating(false);
    }
  };

  // --- Drag Logic ---
  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!image) return;

    // Default to dragging image
    setIsDraggingImage(true);

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
    setDragStart({ x: clientX, y: clientY });
  };

  const handleTextMouseDown = (e: React.MouseEvent | React.TouchEvent, id: string) => {
    e.stopPropagation(); // Don't drag background
    setActiveTextId(id);
    setIsDraggingText(true);
    setActiveTab('text'); // Switch UI to text controls

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
    setDragStart({ x: clientX, y: clientY });
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if ((!isDraggingImage && !isDraggingText) || !containerRef.current) return;

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;

    const deltaX = clientX - dragStart.x;
    const deltaY = clientY - dragStart.y;
    const rect = containerRef.current.getBoundingClientRect();

    // Percentage based delta
    const percentX = (deltaX / rect.width) * 100;
    const percentY = (deltaY / rect.height) * 100;

    if (isDraggingImage) {
      setEditState(prev => ({
        ...prev,
        translateX: prev.translateX + percentX,
        translateY: prev.translateY + percentY
      }));
    } else if (isDraggingText && activeTextId) {
      setEditState(prev => ({
        ...prev,
        textLayers: prev.textLayers.map(layer => 
          layer.id === activeTextId ? { ...layer, x: layer.x + percentX, y: layer.y + percentY } : layer
        )
      }));
    }

    setDragStart({ x: clientX, y: clientY });
  };

  const handleMouseUp = () => {
    setIsDraggingImage(false);
    setIsDraggingText(false);
  };

  // --- Text Logic ---
  const addTextLayer = () => {
    const newLayer: TextLayer = {
      id: Math.random().toString(36).substr(2, 9),
      text: 'SkinForge',
      fontFamily: FONTS[0].family,
      color: '#ffffff',
      fontSize: 15,
      x: 50,
      y: 50,
      rotation: 0
    };
    setEditState(prev => ({ ...prev, textLayers: [...prev.textLayers, newLayer] }));
    setActiveTextId(newLayer.id);
  };

  const updateActiveText = (key: keyof TextLayer, value: any) => {
    if (!activeTextId) return;
    setEditState(prev => ({
      ...prev,
      textLayers: prev.textLayers.map(l => l.id === activeTextId ? { ...l, [key]: value } : l)
    }));
  };

  const deleteActiveText = () => {
    if (!activeTextId) return;
    setEditState(prev => ({
      ...prev,
      textLayers: prev.textLayers.filter(l => l.id !== activeTextId)
    }));
    setActiveTextId(null);
  };

  const resetAdjustments = () => {
    setEditState(prev => ({
      ...prev,
      brightness: 100,
      contrast: 100,
      saturation: 100,
      grayscale: 0,
      blur: 0
    }));
  };

  const resetTransforms = () => {
    setEditState(prev => ({
      ...prev,
      scale: 1,
      translateX: 0,
      translateY: 0,
      rotation: 0,
      flipX: false,
      flipY: false
    }));
  };

  // CSS Filter String for Preview
  const previewFilter = `brightness(${editState.brightness}%) contrast(${editState.contrast}%) saturate(${editState.saturation}%) grayscale(${editState.grayscale}%) blur(${editState.blur}px)`;
  const activeTextLayer = editState.textLayers.find(l => l.id === activeTextId);

  return (
    <div className="flex flex-col md:flex-row h-[calc(100vh-64px)] bg-black overflow-hidden">

