const App: React.FC = () => {
  const [selectedModel, setSelectedModel] = useState<PhoneModel | null>(null);

  const handleHome = () => {
    if (confirm("Go back to home? Unsaved changes will be lost.")) {
      setSelectedModel(null);
    }
  };

  const handleHomeInstant = () => {
     setSelectedModel(null);
  };

  return (
    <div className="min-h-screen bg-black text-white selection:bg-brand-500/30">
      <Header onHome={selectedModel ? handleHome : handleHomeInstant} />

      <main>
        {!selectedModel ? (
          <ModelSelector onSelect={setSelectedModel} />
        ) : (
          <ImageCustomizer 
            model={selectedModel} 
            onBack={handleHome} 
          />
        )}
      </main>
    </div>
  );
};

