import React, { useState } from 'react';
import { PhoneModel, Brand } from '../types';
import { PHONE_MODELS } from '../constants';
import { Search, ChevronRight, ScanLine, Loader2, Plus, Wifi } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  onSelect: (model: PhoneModel) => void;
}

// Helper to map AI-detected camera styles to SVG paths
const getCameraPathForStyle = (style: string): string => {
  const genericPaths: Record<string, string> = {
    'island_left': "M 12 12 h 28 a 8 8 0 0 1 8 8 v 28 a 8 8 0 0 1 -8 8 h -28 a 8 8 0 0 1 -8 -8 v -28 a 8 8 0 0 1 8 -8 z", // iPhone Style
    'vertical_left': "M 10 10 h 22 a 6 6 0 0 1 6 6 v 40 a 6 6 0 0 1 -6 6 h -22 a 6 6 0 0 1 -6 -6 v -40 a 6 6 0 0 1 6 -6 z", // Galaxy Base Style
    'bar_center': "M 0 24 h 100 v 22 h -100 z M 8 30 h 30 a 5 5 0 0 1 5 5 v 0 a 5 5 0 0 1 -5 5 h -30 a 5 5 0 0 1 -5 -5 v 0 a 5 5 0 0 1 5 -5 z", // Pixel Style
    'circle_center': "M 35 15 a 15 15 0 1 0 30 0 a 15 15 0 1 0 -30 0", // Generic Circular
    'default': "M 10 10 h 20 v 20 h -20 z"
  };
  return genericPaths[style] || genericPaths['island_left'];
};

export const ModelSelector: React.FC<Props> = ({ onSelect }) => {
  const [activeBrand, setActiveBrand] = useState<Brand | 'All'>('All');
  const [search, setSearch] = useState('');
  const [models, setModels] = useState<PhoneModel[]>(PHONE_MODELS);
  const [is scanning, setIsScanning] = useState(false);

  const filteredModels = models.filter(m => {
    const matchesBrand = activeBrand === 'All' || m.brand === activeBrand;
    const matchesSearch = m.name.toLowerCase().includes(search.toLowerCase());
    return matchesBrand && matchesSearch;
  });

  const handleNeuralScan = async () => {
    if (!search.trim()) return;
    setIsScanning(true);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Request structured data from Gemini
      const response = await ai.models.generateContent({
        model: "gemini-2.5-flash-preview", // Fast model for data retrieval
        contents: `Find the exact physical technical specifications for the smartphone: "${search}". 
                   I need the body dimensions in millimeters. 
                   Also determine the brand and the style of the rear camera layout.
                   Camera styles options: 'island_left' (like iPhone), 'vertical_left' (like Samsung S24), 'bar_center' (like Pixel), 'circle_center' (like OnePlus).`,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.OBJECT,
            properties: {
              found: { type: Type.BOOLEAN },
              brand: { type: Type.STRING, enum: [Brand.APPLE, Brand.SAMSUNG, Brand.GOOGLE, "Other"] },
              widthMm: { type: Type.NUMBER, description: "Width in mm" },
              heightMm: { type: Type.NUMBER, description: "Height in mm" },
              cornerRadiusMm: { type: Type.NUMBER, description: "Approximated corner radius in mm (usually 8-14mm)" },
              releaseYear: { type: Type.NUMBER },
              cameraStyle: { type: Type.STRING, enum: ['island_left', 'vertical_left', 'bar_center', 'circle_center'] }
            }
          }
        }
      });

      const data = JSON.parse(response.text);

      if (data && data.found) {
        const newModel: PhoneModel = {
          id: search.toLowerCase().replace(/\s+/g, '-'),
          name: search, // Use user search term or capitalize it
          brand: data.brand as Brand,
          widthMm: data.widthMm,
          heightMm: data.heightMm,
          cornerRadiusMm: data.cornerRadiusMm || 10,
          releaseYear: data.releaseYear,
          cameraPath: getCameraPathForStyle(data.cameraStyle)
        };

        setModels(prev => [newModel, ...prev]);
        setActiveBrand('All'); // Switch to all to see the new item
        onSelect(newModel); // Auto-select found model? Or just show it. Let's just show it.
      } else {
        alert("Could not retrieve precise specifications for this device. Please try a more specific model name.");
      }

    } catch (error) {
      console.error("Neural Scan failed", error);
      alert("Neural Scan failed. Please check connection.");
    } finally {
      setIsScanning(false);
    }
  };

  return (
    <div className="w-full max-w-4xl mx-auto p-4 md:p-8 animate-fade-in pb-20">
      <div className="text-center mb-8 md:mb-10">
        <h1 className="text-4xl md:text-6xl font-bold text-white mb-3 md:mb-4 font-['Oswald'] uppercase tracking-tighter">
          <span className="text-transparent bg-clip-text bg-gradient-to-r from-brand-400 to-violet-400">Device</span>
        </h1>
        <p className="text-sm md:text-base text-zinc-400 max-w-xl mx-auto leading-relaxed font-medium">
          Forge your signature style and print it into reality.
        </p>
      </div>

