import React, { useState } from 'react';
import { PhoneModel, Brand } from '../types';
import { PHONE_MODELS } from '../constants';
import { Search, ChevronRight, ScanLine, Loader2, Plus, Wifi, ExternalLink } from 'lucide-react';
import { GoogleGenAI, Type } from "@google/genai";

interface Props {
  onSelect: (model: PhoneModel) => void;
}

// Helper to map AI-detected camera styles to SVG paths
const getCameraPathForStyle = (style: string): string => {
  const genericPaths: Record<string, string> = {
    'island_left': "M 12 12 h 28 a 8 8 0 0 1 8 8 v 28 a 8 8 0 0 1 -8 8 h -28 a 8 8 0 0 1 -8 -8 v -28 a 8 8 0 0 1 8 -8 z", // iPhone Style
    'vertical_left': "M 10 10 h 22 a 6 6 0 0 1 6 6 v 40 a 6 6 0 0 1 -6 6 h -22 a 6 6 0 0 1 -6 -6 v -40 a 6 6 0 0 1 6 -6 z", // Galaxy Base Style
    'bar_center': "M 0 24 h 100 v 22 h -100 z M 8 30 h 30 a 5 5 0 0 1 5 5 v 0 a 5 5 0 0 1 -5 5 h -30 a 5 5 0 0 1 -5 -5 v 0 a 5 5 0 0 1 5 -5 z", // Pixel Style
    'circle_center': "M 35 15 a 15 15 0 1 0 30 0 a 15 15 0 1 0 -30 0", // Generic Circular
    'default': "M 10 10 h 20 v 20 h -20 z"
  };
  return genericPaths[style] || genericPaths['island_left'];
};

export const ModelSelector: React.FC<Props> = ({ onSelect }) => {
  const [activeBrand, setActiveBrand] = useState<Brand | 'All'>('All');
  const [search, setSearch] = useState('');
  const [models, setModels] = useState<PhoneModel[]>(PHONE_MODELS);
  const [isScanning, setIsScanning] = useState(false);
  const [scanSources, setScanSources] = useState<{title: string, uri: string}[]>([]);

  const filteredModels = models.filter(m => {
    const matchesBrand = activeBrand === 'All' || m.brand === activeBrand;
    const searchLower = search.toLowerCase();
    const matchesSearch = m.name.toLowerCase().includes(searchLower) || 
                          m.brand.toLowerCase().includes(searchLower);
    return matchesBrand && matchesSearch;
  });

  const handleNeuralScan = async () => {
    if (!search.trim()) return;
    setIsScanning(true);
    setScanSources([]);

    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      // Use googleSearch tool for real-world accuracy
      // We cannot use responseSchema with googleSearch in all cases, so we request JSON in text.
      const response = await ai.models.generateContent({
        model: "gemini-3-flash-preview", 
        contents: `Retrieve the official physical body dimensions (height, width) for "${search}" in millimeters.
                   Search for "gsmarena ${search} dimensions" or official manufacturer specs.

                   Return a JSON object. Do not include markdown formatting.

                   JSON Structure:
                   {
                     "found": boolean,
                     "brand": "Apple" | "Samsung" | "Google" | "Other",
                     "widthMm": number, // The shorter side of the phone body
                     "heightMm": number, // The longer side of the phone body
                     "cornerRadiusMm": number, // Estimate: 1-3 for boxy/sharp phones (S24 Ultra), 8-15 for rounded phones (iPhone, Pixel)
                     "releaseYear": number,
                     "cameraStyle": "island_left" | "vertical_left" | "bar_center" | "circle_center"
                   }`,
        config: {
          tools: [{googleSearch: {}}]
        }
      });

      // 1. Extract Sources from Grounding Metadata
      const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
      const sources = chunks
        .map((c: any) => c.web ? { title: c.web.title, uri: c.web.uri } : null)
        .filter((s): s is {title: string, uri: string} => !!s);

      setScanSources(sources);

      // 2. Parse JSON from text response
      let text = response.text || "";
      // Sanitize markdown code blocks if present
      text = text.replace(/```json\n?|```/g, '').trim();

      // Find JSON object if there is extra text
      const jsonMatch = text.match(/\{[\s\S]*\}/);
      if (jsonMatch) {
        text = jsonMatch[0];
      }

      const data = JSON.parse(text);

      if (data && data.found) {
        const newModel: PhoneModel = {
          id: search.toLowerCase().replace(/\s+/g, '-'),
          name: search, // Use user search term or capitalize it
          brand: data.brand as Brand,
          widthMm: data.widthMm,
          heightMm: data.heightMm,
          cornerRadiusMm: data.cornerRadiusMm || 10,
          releaseYear: data.releaseYear,
          cameraPath: getCameraPathForStyle(data.cameraStyle)
        };

        setModels(prev => [newModel, ...prev]);
        setActiveBrand('All'); // Switch to all to see the new item
        // Do not auto-select immediately so user can see the "Found" state and sources if they want
        // But for UX flow, maybe auto-select is better? 
        // Let's keep it in the list and highlight it effectively by filtering.
      } else {
        alert("Could not retrieve precise specifications for this device. Please try a more specific model name.");
      }

    } catch (error) {
      console.error("Neural Scan failed", error);
      alert("Neural Scan failed. Please check connection.");
