import React, { ErrorInfo, ReactNode } from 'react';
import { AlertTriangle, RefreshCw } from 'lucide-react';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
  error: Error | null;
}

export class ErrorBoundary extends React.Component<Props, State> {
  public state: State = {
    hasError: false,
    error: null
  };

  public static getDerivedStateFromError(error: Error): State {
    return { hasError: true, error };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-screen bg-black text-white flex flex-col items-center justify-center p-4">
          <div className="bg-zinc-900 border border-red-500/20 rounded-2xl p-8 max-w-md w-full text-center shadow-2xl">
            <div className="w-16 h-16 bg-red-500/10 rounded-full flex items-center justify-center mx-auto mb-4 text-red-500">
              <AlertTriangle size={32} />
            </div>
            <h1 className="text-xl font-bold mb-2">Something went wrong</h1>
            <p className="text-zinc-400 text-sm mb-6">
              The application encountered an unexpected error.
            </p>
            <div className="bg-black/30 p-3 rounded-lg text-left mb-6 overflow-hidden">
                <code className="text-xs text-red-300 font-mono break-all">
                    {this.state.error?.message}
                </code>
            </div>
            <button
              onClick={() => window.location.reload()}
              className="w-full py-3 bg-white text-black font-bold rounded-xl hover:bg-zinc-200 transition-colors flex items-center justify-center gap-2"
            >
              <RefreshCw size={16} /> Reload Application
            </button>
          </div>
        </div>
      );
    }

    return this.props.children;
  }
}

import React, { useState, useRef, useEffect } from 'react';
import { PhoneModel, EditState, TextLayer } from '../types';
import { DEFAULT_PATTERNS, FONTS } from '../constants';
import { generatePrintablePdf } from '../utils/canvasUtils';
import { GoogleGenAI } from "@google/genai";
import { 
  Upload, Sliders, Move, ArrowLeft, Download, 
  RotateCcw, ZoomIn, FlipHorizontal, FlipVertical,
  Image as ImageIcon, RefreshCw, Sun, Contrast, Droplet, EyeOff, Aperture,
  Type, Plus, Trash2, Sparkles, Wand2, Loader2, ChevronDown
} from 'lucide-react';

interface Props {
  model: PhoneModel;
  onBack: () => void;
}

const INITIAL_STATE: EditState = {
  scale: 1,
  translateX: 0,
  translateY: 0,
  rotation: 0,
  brightness: 100,
  contrast: 100,
  saturation: 100,
  grayscale: 0,
  blur: 0,
  flipX: false,
  flipY: false,
  textLayers: []
};

type ToolTab = 'upload' | 'adjust' | 'transform' | 'text' | 'export';

export const ImageCustomizer: React.FC<Props> = ({ model, onBack }) => {
  const [image, setImage] = useState<string | null>(null);
  const [editState, setEditState] = useState<EditState>(INITIAL_STATE);
  const [activeTab, setActiveTab] = useState<ToolTab>('upload');
  const [activeTextId, setActiveTextId] = useState<string | null>(null);
  const [isPanelOpen, setIsPanelOpen] = useState(true); // For mobile toggle

  const [isDraggingImage, setIsDraggingImage] = useState(false);
  const [isDraggingText, setIsDraggingText] = useState(false);
  const [dragStart, setDragStart] = useState({ x: 0, y: 0 });
  const [isGenerating, setIsGenerating] = useState(false);

  // Pinch Zoom Refs
  const initialPinchDistance = useRef<number | null>(null);
  const startPinchScale = useRef<number>(1);

  // AI Generation State
  const [aiPrompt, setAiPrompt] = useState('');
  const [isAiGenerating, setIsAiGenerating] = useState(false);

  const containerRef = useRef<HTMLDivElement>(null);

  // Auto-switch tab on image upload
  useEffect(() => {
    if (image && activeTab === 'upload' && window.innerWidth < 768) {
       // On mobile, keep panel open but switch tab to transform to encourage interaction
       setActiveTab('transform');
    }
  }, [image]);

  // File Upload
  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onload = (ev) => {
        setImage(ev.target?.result as string);
        setEditState({ ...INITIAL_STATE, textLayers: [] }); 
        setActiveTab('transform'); 
      };
      reader.readAsDataURL(file);
    }
  };

  // AI Generation
  const handleAiGeneration = async () => {
    if (!aiPrompt.trim()) return;
    setIsAiGenerating(true);
    try {
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });
      const fullPrompt = `High resolution, 4k, detailed, artistic wallpaper of ${aiPrompt}`;

      const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash-image',
        contents: {
          parts: [{ text: fullPrompt }],
        },
      });

      let foundImage = false;
      if (response.candidates?.[0]?.content?.parts) {
        for (const part of response.candidates[0].content.parts) {
          if (part.inlineData) {
            const base64EncodeString = part.inlineData.data;
            const mimeType = part.inlineData.mimeType || 'image/png';
            const imageUrl = `data:${mimeType};base64,${base64EncodeString}`;
            setImage(imageUrl);
            setEditState({ ...INITIAL_STATE, textLayers: [] });
            setActiveTab('transform');
            foundImage = true;
            break;
          }
        }
      }

      if (!foundImage) {
          alert("No image was generated. Please try a different prompt.");
      }
    } catch (error) {
      console.error("AI Generation failed", error);
      alert("Failed to generate image. Please try again.");
    } finally {
      setIsAiGenerating(false);
    }
  };

  // PDF Generation
  const handleDownload = async () => {
    if (!image) return;
    setIsGenerating(true);
    try {
      await generatePrintablePdf(model, image, editState);
    } catch (err) {
      console.error(err);
      alert('Failed to generate PDF. Please try again.');
    } finally {
      setIsGenerating(false);
    }
  };

  // --- Drag & Zoom Logic ---
  const handleMouseDown = (e: React.MouseEvent | React.TouchEvent) => {
    if (!image) return;

    // Check for Pinch Start (2 fingers)
    if ('touches' in e && e.touches.length === 2) {
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );
      initialPinchDistance.current = dist;
      startPinchScale.current = editState.scale;
      setIsDraggingImage(false); // Cancel drag if it started
      return;
    }

    setIsDraggingImage(true);
    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
    setDragStart({ x: clientX, y: clientY });
  };

  const handleTextMouseDown = (e: React.MouseEvent | React.TouchEvent, id: string) => {
    e.stopPropagation(); 
    setActiveTextId(id);
    setIsDraggingText(true);
    setActiveTab('text'); 
    setIsPanelOpen(true);

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
    setDragStart({ x: clientX, y: clientY });
  };

  const handleMouseMove = (e: React.MouseEvent | React.TouchEvent) => {
    if (!containerRef.current) return;

    // Handle Pinch Zoom Move
    if ('touches' in e && e.touches.length === 2 && initialPinchDistance.current !== null) {
      const dist = Math.hypot(
        e.touches[0].clientX - e.touches[1].clientX,
        e.touches[0].clientY - e.touches[1].clientY
      );

      if (dist > 0) {
        const scaleFactor = dist / initialPinchDistance.current;
        // Limit scale between 0.1 and 5
        const newScale = Math.max(0.1, Math.min(startPinchScale.current * scaleFactor, 5));

        setEditState(prev => ({
          ...prev,
          scale: newScale
        }));
      }
      return;
    }

    if ((!isDraggingImage && !isDraggingText)) return;

    // For touch events, we need to prevent default scrolling if dragging
    // However, touch-action: none on container handles this better than e.preventDefault()

    const clientX = 'touches' in e ? e.touches[0].clientX : (e as React.MouseEvent).clientX;
    const clientY = 'touches' in e ? e.touches[0].clientY : (e as React.MouseEvent).clientY;
    const deltaX = clientX - dragStart.x;
    const deltaY = clientY - dragStart.y;
    const rect = containerRef.current.getBoundingClientRect();

    // Safety check for zero dimensions
    if (rect.width === 0 || rect.height === 0) return;

    const percentX = (deltaX / rect.width) * 100;
    const percentY = (deltaY / rect.height) * 100;

    if (isDraggingImage) {
      setEditState(prev => ({
        ...prev,
        translateX: prev.translateX + percentX,
        translateY: prev.translateY + percentY
      }));
    } else if (isDraggingText && activeTextId) {
      setEditState(prev => ({
        ...prev,
        textLayers: prev.textLayers.map(layer => 
          layer.id === activeTextId ? { ...layer, x: layer.x + percentX, y: layer.y + percentY } : layer
        )
      }));
    }
    setDragStart({ x: clientX, y: clientY });
  };

  const handleMouseUp = () => {
    setIsDraggingImage(false);
    setIsDraggingText(false);
    initialPinchDistance.current = null; // Reset pinch
  };

  // --- Text Logic ---
  const addTextLayer = () => {
    const newLayer: TextLayer = {
      id: Math.random().toString(36).substr(2, 9),
      text: 'SkinForge',
      fontFamily: FONTS[0].family,
      color: '#ffffff',
      fontSize: 15,
      x: 50,
      y: 50,
      rotation: 0
    };
    setEditState(prev => ({ ...prev, textLayers: [...prev.textLayers, newLayer] }));
    setActiveTextId(newLayer.id);
  };

  const updateActiveText = (key: keyof TextLayer, value: any) => {
    if (!activeTextId) return;
    setEditState(prev => ({
      ...prev,
      textLayers: prev.textLayers.map(l => l.id === activeTextId ? { ...l, [key]: value } : l)
    }));
  };

  const deleteActiveText = () => {
    if (!activeTextId) return;
    setEditState(prev => ({
      ...prev,
      textLayers: prev.textLayers.filter(l => l.id !== activeTextId)
    }));
    setActiveTextId(null);
  };

  const resetAdjustments = () => {
    setEditState(prev => ({
      ...prev,
      brightness: 100,
      contrast: 100,
      saturation: 100,
      grayscale: 0,
      blur: 0
